 * @param {number} pos The position of the person in question.
 * @param {number} k The required number of visible people.
 * @returns {number} The number of possible direction assignments modulo 10^9 + 7.
 */
function solve(n, pos, k) {
    const MOD = 1000000007n;

    // Number of people to the left of pos (indices 0 to pos-1)
    const leftCount = pos;
    // Number of people to the right of pos (indices pos+1 to n-1)
